package main

import (
    "context"
    "net/http"
    "time"
)

type HttpServer struct {
    server_instance *http.Server
    mux             *http.ServeMux
}

func (h *HttpServer) startServer() {
    h.mux = http.NewServeMux()
    h.server_instance = &http.Server{Addr: ":8080", Handler: h.mux}
    go h.server_instance.ListenAndServe()
}

func (h *HttpServer) handleRequest(path string, handler func(http.ResponseWriter, *http.Request)) {
    h.mux.HandleFunc(path, handler)
}

func (h *HttpServer) shutdownServer() error {
    ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
    defer cancel()
    return h.server_instance.Shutdown(ctx)
}
