#include <vector>
#include <queue>
#include <functional>
#include <thread>
#include <mutex>
#include <condition_variable>

class ThreadPool {
public:
    ThreadPool(size_t num_threads) : shutdown_flag_(false) {
        worker_threads_.reserve(num_threads);
        for (size_t i = 0; i < num_threads; ++i) {
            worker_threads_.emplace_back(&ThreadPool::worker, this);
        }
    }

    ~ThreadPool() {
        shutdownNow();
    }

    template<typename F>
    void addTask(F&& task) {
        {
            std::unique_lock<std::mutex> lock(queue_mutex_);
            task_queue_.emplace(std::forward<F>(task));
        }
        queue_condition_.notify_one();
    }

    void shutdownNow() {
        {
            std::unique_lock<std::mutex> lock(queue_mutex_);
            shutdown_flag_ = true;
        }
        queue_condition_.notify_all();
        for (auto& thread : worker_threads_) {
            if (thread.joinable()) {
                thread.join();
            }
        }
    }

private:
    void worker() {
        while (true) {
            std::unique_lock<std::mutex> lock(queue_mutex_);
            queue_condition_.wait(lock, [this]() {
                return !task_queue_.empty() || shutdown_flag_;
            });

            if (shutdown_flag_) break;

            if (!task_queue_.empty()) {
                auto task = std::move(task_queue_.front());
                task_queue_.pop();
                lock.unlock();
                task();
            }
        }
    }

    std::queue<std::function<void()>> task_queue_;
    std::vector<std::thread> worker_threads_;
    std::mutex queue_mutex_;
    std::condition_variable queue_condition_;
    bool shutdown_flag_;
};
