```go
package fileutil

import (
	"bufio"
	"errors"
	"io"
	"os"
	"sync"

	"golang.org/x/text/encoding"
	"golang.org/x/text/encoding/unicode"
)

type FileReader struct {
	file     *os.File
	reader   *bufio.Reader
	decoder *encoding.Decoder
	once     sync.Once
}

func NewFileReader(path string) (*FileReader, error) {
	file, err := os.Open(path)
	if err != nil {
		return nil, err
	}

	peekBuffer := make([]byte, 1024)
	n, _ := io.ReadFull(file, peekBuffer)
	_, encodingName, _ := detectEncoding(peekBuffer[:n])
	if _, err := file.Seek(0, io.SeekStart); err != nil {
		return nil, err
	}

	var dec *encoding.Decoder
	switch encodingName {
	case "utf-8":
		dec = unicode.UTF8.NewDecoder()
	case "utf-16be":
		dec = unicode.UTF16(unicode.BigEndian, unicode.UseBOM).NewDecoder()
	case "utf-16le":
		dec = unicode.UTF16(unicode.LittleEndian, unicode.UseBOM).NewDecoder()
	default:
		dec = unicode.UTF8.NewDecoder()
	}

	return &FileReader{
		file:     file,
		reader:   bufio.NewReaderSize(encoding.NewDecoderReader(file, dec), 4096),
		decoder: dec,
	}, nil
}

func (fr *FileReader) ReadAllLines() (<-chan interface{}, error) {
	if fr.file == nil {
		return nil, errors.New("file handle closed")
	}

	outputChan := make(chan interface{})
	go func() {
		defer close(outputChan)
		for {
			line, err := fr.reader.ReadString('\n')
			if err != nil {
				if err != io.EOF {
					outputChan <- err
				}
				break
			}
			outputChan <- line
		}
	}()
	return outputChan, nil
}

func (fr *FileReader) CloseHandle() {
	fr.once.Do(func() {
		if fr.file != nil {
			fr.file.Close()
			fr.file = nil
		}
	})
}

func detectEncoding(b []byte) ([]byte, string, bool) {
	if len(b) >= 2 {
		switch {
		case b[0] == 0xFE && b[1] == 0xFF:
			return b[2:], "utf-16be", true
		case b[0] == 0xFF && b[1] == 0xFE:
			return b[2:], "utf-16le", true
		}
	}
	if len(b) >= 3 && b[0] == 0xEF && b[1] == 0xBB && b[2] == 0xBF {
		return b[3:], "utf-8", true
	}
	return b, "utf-8", false
}
