mod geometry {
    #[derive(Debug)]
    pub struct Circle {
        x: f64,
        y: f64,
        radius: f64,
    }

    impl Circle {
        pub fn new(x: f64, y: f64, radius: f64) -> Self {
            assert!(radius >= 0.0, "Radius must be non-negative.");
            Self { x, y, radius }
        }

        pub fn calculate_area(&self, pi_value: f64) -> f64 {
            pi_value * self.radius.powi(2)
        }

        pub fn set_radius(&mut self, new_radius: f64) {
            assert!(new_radius >= 0.0, "Radius must be non-negative.");
            self.radius = new_radius;
        }

        pub fn collides_with(&self, other: &Self) -> bool {
            let dx = self.x - other.x;
            let dy = self.y - other.y;
            let distance_squared = dx.mul_add(dx, dy * dy);
            let sum_radii = self.radius + other.radius;
            distance_squared <= sum_radii * sum_radii
        }
    }
}
