const std = @import("std");
const Allocator = std.mem.Allocator;

const ParseError = error {
    invalid_syntax_error,
    invalid_escape_error,
    duplicate_section_error,
    key_not_found_error,
    type_coercion_error,
};

const Value = union(enum) {
    string: []const u8,
    integer: i64,
    boolean: bool,
};

const IniSection = struct {
    allocator: Allocator,
    parent: ?*IniSection,
    name: []const u8,
    subsections: std.StringHashMap(*IniSection),
    kv_map: std.StringHashMap([]const u8),

    pub fn init(allocator: Allocator, name: []const u8, parent: ?*IniSection) !*IniSection {
        const self = try allocator.create(IniSection);
        self.* = .{
            .allocator = allocator,
            .parent = parent,
            .name = try allocator.dupe(u8, name),
            .subsections = std.StringHashMap(*IniSection).init(allocator),
            .kv_map = std.StringHashMap([]const u8).init(allocator),
        };
        return self;
    }

    pub fn deinit(self: *IniSection) void {
        var sub_it = self.subsections.iterator();
        while (sub_it.next()) |entry| {
            entry.value_ptr.deinit();
            self.allocator.destroy(entry.value_ptr);
        }
        self.subsections.deinit();
        var kv_it = self.kv_map.iterator();
        while (kv_it.next()) |entry| {
            self.allocator.free(entry.key_ptr.*);
            self.allocator.free(entry.value_ptr.*);
        }
        self.kv_map.deinit();
        self.allocator.free(self.name);
    }

    pub fn getValue(self: *const IniSection, key: []const u8) ParseError!Value {
        const raw_value = self.kv_map.get(key) orelse return ParseError.key_not_found_error;
        if (std.fmt.parseInt(i64, raw_value, 10)) |int| {
            return Value{ .integer = int };
        } else |_| {}
        if (std.ascii.eqlIgnoreCase(raw_value, "true")) return Value{ .boolean = true };
        if (std.ascii.eqlIgnoreCase(raw_value, "false")) return Value{ .boolean = false };
        return Value{ .string = raw_value };
    }

    pub fn addKeyValuePair(self: *IniSection, key: []const u8, value: []const u8, resolver: ?*const fn (existing: []const u8, new: []const u8) []const u8) !void {
        const dup_key = try self.allocator.dupe(u8, key);
        const dup_val = try self.allocator.dupe(u8, value);
        errdefer {
            self.allocator.free(dup_key);
            self.allocator.free(dup_val);
        }
        if (self.kv_map.get(dup_key)) |existing| {
            if (resolver) |resolve| {
                const resolved = resolve(existing, dup_val);
                try self.kv_map.put(dup_key, resolved);
            } else {
                try self.kv_map.put(dup_key, dup_val);
            }
        } else {
            try self.kv_map.put(dup_key, dup_val);
        }
    }
};

fn parseIni(allocator: Allocator, input: []const u8) !*IniSection {
    var root = try IniSection.init(allocator, "root", null);
    var current_section = root;
    var lines = std.mem.splitSequence(u8, input, "\n");
    var buffer = std.ArrayList(u8).init(allocator);
    defer buffer.deinit();

    while (true) {
        const line = lines.next() orelse break;
        const trimmed = std.mem.trim(u8, line, " \t\r");

        if (trimmed.len == 0 or trimmed[0] == ';' or trimmed[0] == '#') {
            continue;
        }

        if (trimmed[trimmed.len - 1] == '\\') {
            try buffer.appendSlice(trimmed[0 .. trimmed.len - 1]);
            continue;
        } else if (buffer.items.len > 0) {
            try buffer.appendSlice(trimmed);
        }

        const full_line = if (buffer.items.len > 0) buffer.items else trimmed;
        if (buffer.items.len > 0) buffer.clearRetainingCapacity();

        if (full_line[0] == '[') {
            const end_idx = std.mem.indexOfScalar(u8, full_line, ']') orelse return ParseError.invalid_syntax_error;
            const parts = std.mem.splitSequence(u8, std.mem.trim(u8, full_line[1..end_idx], " \t"), ".");
            var parent: ?*IniSection = root;
            current_section = root;

            while (parts.next()) |part| {
                const trimmed_part = std.mem.trim(u8, part, " \t");
                if (current_section.subsections.get(trimmed_part)) |subsection| {
                    parent = current_section;
                    current_section = subsection;
                } else {
                    const new_section = try IniSection.init(allocator, trimmed_part, parent);
                    try current_section.subsections.put(trimmed_part, new_section);
                    parent = current_section;
                    current_section = new_section;
                }
            }
        } else {
            const sep_idx = std.mem.indexOfAny(u8, full_line, "=:") orelse return ParseError.invalid_syntax_error;
            const key = std.mem.trim(u8, full_line[0..sep_idx], " \t");
            const raw_value = std.mem.trim(u8, full_line[sep_idx + 1 ..], " \t");
            const processed_value = try processEscapes(allocator, raw_value);
            try current_section.addKeyValuePair(key, processed_value, null);
            allocator.free(processed_value);
        }
    }

    return root;
}

fn processEscapes(allocator: Allocator, input: []const u8) ![]const u8 {
    var result = std.ArrayList(u8).init(allocator);
    var i: usize = 0;

    while (i < input.len) {
        if (input[i] == '\\') {
            i += 1;
            if (i >= input.len) return ParseError.invalid_escape_error;
            switch (input[i]) {
                'n' => try result.append('\n'),
                't' => try result.append('\t'),
                'r' => try result.append('\r'),
                '\\' => try result.append('\\'),
                else => return ParseError.invalid_escape_error,
            }
        } else {
            try result.append(input[i]);
        }
        i += 1;
    }

    return result.toOwnedSlice();
}
