#include <queue>
#include <mutex>
#include <condition_variable>
#include <chrono>
#include <utility>

template<typename T, typename AllocationPolicy>
class ThreadSafeQueue {
public:
    explicit ThreadSafeQueue(const AllocationPolicy& policy = AllocationPolicy())
        : allocation_policy_(policy) {}

    template<typename U, typename Rep, typename Period>
    bool pushBack(U&& element, const std::chrono::duration<Rep, Period>& timeout) {
        std::unique_lock<std::mutex> lock(mutex_);
        const auto deadline = std::chrono::steady_clock::now() + timeout;
        while (queue_.size() >= allocation_policy_.maxSize()) {
            if (not_full_.wait_until(lock, deadline) == std::cv_status::timeout) {
                return false;
            }
        }
        queue_.emplace_back(std::forward<U>(element));
        not_empty_.notify_one();
        return true;
    }

    T popFront() {
        std::unique_lock<std::mutex> lock(mutex_);
        not_empty_.wait(lock, [this] { return !queue_.empty(); });
        T element = std::move(queue_.front());
        queue_.pop_front();
        not_full_.notify_one();
        return element;
    }

private:
    std::mutex mutex_;
    std::condition_variable not_full_;
    std::condition_variable not_empty_;
    std::deque<T> queue_;
    AllocationPolicy allocation_policy_;
};
