const std = @import("std");
const Crc32 = std.hash.Crc32;

const PacketError = error{
    invalid_version_error,
    checksum_mismatch_error,
    malformed_header_error,
};

const Header = packed struct {
    version: u4,
    ihl: u4,
    length: u16,
    identification: u16,
    flags: u3,
    fragment_offset: u13,
    ttl: u8,
    protocol: u8,
    header_checksum: u16,
    source_address: u32,
    dest_address: u32,
};

const QuarantineEntry = struct {
    data: []const u8,
    reason: []const u8,
};

pub const PacketDecoder = struct {
    allocator: std.mem.Allocator,
    quarantine: std.ArrayList(QuarantineEntry),

    pub fn init(allocator: std.mem.Allocator) PacketDecoder {
        return .{
            .allocator = allocator,
            .quarantine = std.ArrayList(QuarantineEntry).init(allocator),
        };
    }

    pub fn deinit(self: *PacketDecoder) void {
        for (self.quarantine.items) |entry| {
            self.allocator.free(entry.data);
        }
        self.quarantine.deinit();
    }

    pub fn readHeader(self: *PacketDecoder, packet_data: []const u8) !Header {
        if (packet_data.len < 20) {
            try self.quarantize(packet_data, "header too short");
            return PacketError.malformed_header_error;
        }

        const version = packet_data[0] >> 4;
        if (version != 4 and version != 6) {
            try self.quarantize(packet_data, "invalid IP version");
            return PacketError.invalid_version_error;
        }

        const raw_header = std.mem.bytesAsValue(Header, packet_data[0..20]);
        var header = raw_header.*;
        header.length = std.mem.bigToNative(u16, header.length);
        header.identification = std.mem.bigToNative(u16, header.identification);
        header.fragment_offset = std.mem.bigToNative(u16, @bitCast(header.fragment_offset));
        header.header_checksum = std.mem.bigToNative(u16, header.header_checksum);
        header.source_address = std.mem.bigToNative(u32, header.source_address);
        header.dest_address = std.mem.bigToNative(u32, header.dest_address);

        return header;
    }

    pub fn validateChecksum(self: *PacketDecoder, packet_data: []const u8) !void {
        const computed = Crc32.hash(packet_data);
        const stored = std.mem.bigToNative(u32, @ptrCast(*const u32, @alignCast(4, packet_data[16..20].ptr)).*);
        if (computed != stored) {
            try self.quarantize(packet_data, "checksum mismatch");
            return PacketError.checksum_mismatch_error;
        }
    }

    fn quarantize(self: *PacketDecoder, data: []const u8, reason: []const u8) !void {
        const copy = try self.allocator.dupe(u8, data);
        errdefer self.allocator.free(copy);
        try self.quarantine.append(.{ .data = copy, .reason = reason });
    }
};
