const std = @import("std");
const math = std.math;

const BitDepth = enum { twelve_bit, sixteen_bit };
const KernelType = enum { sobel, prewitt };

pub const PixelMatrix = struct {
    data: []u16,
    width: usize,
    height: usize,
    bit_depth: BitDepth,
    allocator: std.mem.Allocator,

    pub fn convertToGrayscale(self: *PixelMatrix) !void {
        const min_hu = -1000;
        const max_hu = 2000;
        const range = max_hu - min_hu;

        for (self.data) |*pixel| {
            const hu = @as(i32, pixel.*) + min_hu;
            const scaled = @floatToInt(u16, (@intToFloat(f32, hu) / range) * math.maxInt(u16));
            pixel.* = scaled;
        }
    }

    pub fn applyKernel(self: *PixelMatrix, kernel_type: KernelType) !void {
        const kernel = switch (kernel_type) {
            .sobel => [2][3][3]i16{
                .{ .{ -1, 0, 1 }, .{ -2, 0, 2 }, .{ -1, 0, 1 } },
                .{ .{ -1, -2, -1 }, .{ 0, 0, 0 }, .{ 1, 2, 1 } },
            },
            .prewitt => [2][3][3]i16{
                .{ .{ -1, 0, 1 }, .{ -1, 0, 1 }, .{ -1, 0, 1 } },
                .{ .{ -1, -1, -1 }, .{ 0, 0, 0 }, .{ 1, 1, 1 } },
            },
        };

        var output = try self.allocator.alloc(u16, self.data.len);
        defer self.allocator.free(output);

        for (self.data) |_, i| {
            const x = i % self.width;
            const y = i / self.width;
            if (x == 0 or x == self.width - 1 or y == 0 or y == self.height - 1) {
                output[i] = self.data[i];
                continue;
            }

            var gx: i32 = 0;
            var gy: i32 = 0;
            for ([_]usize{ 0, 1, 2 }) |kx| {
                for ([_]usize{ 0, 1, 2 }) |ky| {
                    const px = x + kx - 1;
                    const py = y + ky - 1;
                    const idx = py * self.width + px;
                    gx += kernel[0][ky][kx] * @as(i32, self.data[idx]);
                    gy += kernel[1][ky][kx] * @as(i32, self.data[idx]);
                }
            }
            const magnitude = @floatToInt(u16, @sqrt(@intToFloat(f32, gx * gx + gy * gy)));
            output[i] = magnitude;
        }
        std.mem.copy(u16, self.data, output);
    }

    pub fn convertTo12Bit(self: *PixelMatrix) !void {
        if (self.bit_depth != .sixteen_bit) return error.invalid_conversion_error;
        for (self.data) |*pixel| {
            pixel.* >>= 4;
        }
        self.bit_depth = .twelve_bit;
    }

    pub fn convertTo16Bit(self: *PixelMatrix) !void {
        if (self.bit_depth != .twelve_bit) return error.invalid_conversion_error;
        for (self.data) |*pixel| {
            pixel.* <<= 4;
        }
        self.bit_depth = .sixteen_bit;
    }

    pub fn anisotropicDiffusion(self: *PixelMatrix, iterations: usize, lambda: f32) !void {
        var temp = try self.allocator.alloc(u16, self.data.len);
        defer self.allocator.free(temp);

        var current = self.data;
        var next = temp;

        for (0..iterations) |_| {
            for (current) |_, i| {
                const x = i % self.width;
                const y = i / self.width;
                if (x == 0 or x == self.width - 1 or y == 0 or y == self.height - 1) {
                    next[i] = current[i];
                    continue;
                }

                const center = @intToFloat(f32, current[i]);
                const north = @intToFloat(f32, current[(y - 1) * self.width + x]);
                const south = @intToFloat(f32, current[(y + 1) * self.width + x]);
                const east = @intToFloat(f32, current[y * self.width + (x + 1)]);
                const west = @intToFloat(f32, current[y * self.width + (x - 1)]);

                const delta = 0.25 * lambda * (north + south + east + west - 4 * center);
                next[i] = @floatToInt(u16, center + delta);
            }
            std.mem.swap([]u16, &current, &next);
        }

        if (iterations % 2 == 1) {
            std.mem.copy(u16, self.data, temp);
        }
    }
};
