from cryptography.fernet import Fernet
import time
import asyncio

class DataTransformer:
    def __init__(self, encryption_key=None):
        self.encryptionKey = encryption_key or Fernet.generate_key()
        self.cachedData = {}
        self.sensitiveFields = []

    async def convert_to_format(self, data, target_format, schema=None):
        self.validate_input(data)
        if schema:
            self._validate_schema(data, schema)
        converted_data = await self._perform_conversion(data, target_format)
        if self.sensitiveFields:
            converted_data = self._encrypt_fields(converted_data)
        self.cache_processed_data(converted_data, 3600)
        return converted_data

    def cache_processed_data(self, data, ttl):
        timestamp = time.time()
        self.cachedData[timestamp] = {'data': data, 'expiry': timestamp + ttl}
        self._clean_expired_cache()

    def validate_input(self, data):
        detected = chardet.detect(data) if isinstance(data, bytes) else chardet.detect(str(data).encode())
        if detected['encoding'] not in ['utf-8', 'ascii']:
            raise ValueError("Unsupported charset")
        return True

    def _validate_schema(self, data, schema):
        pass

    async def _perform_conversion(self, data, target_format):
        if target_format == 'json':
            return await self._convert_to_json(data)
        elif target_format == 'xml':
            return await self._convert_to_xml(data)
        elif target_format == 'csv':
            return await self._convert_to_csv(data)
        else:
            raise ValueError("Unsupported format")

    def _encrypt_fields(self, data):
        fernet = Fernet(self.encryptionKey)
        encrypted_data = data.copy()
        for field in self.sensitiveFields:
            if field in encrypted_data:
                encrypted_data[field] = fernet.encrypt(str(encrypted_data[field]).encode()).decode()
        return encrypted_data

    def _clean_expired_cache(self):
        current_time = time.time()
        expired_keys = [k for k, v in self.cachedData.items() if v['expiry'] <= current_time]
        for key in expired_keys:
            del self.cachedData[key]

    async def _convert_to_json(self, data):
        return json.dumps(data)

    async def _convert_to_xml(self, data):
        root = ET.Element('Data')
        for key, value in data.items():
            ET.SubElement(root, key).text = str(value)
        return ET.tostring(root)

    async def _convert_to_csv(self, data):
        output = []
        writer = csv.DictWriter(output, fieldnames=data.keys())
        writer.writeheader()
        writer.writerow(data)
        return '\n'.join(output)
