const { EventEmitter } = require('events');
const protobuf = require('protobufjs');
const Ajv = require('ajv');

class WebSocketManager extends EventEmitter {
  constructor(config) {
    super();
    this.serverUrls = config['server-urls'];
    this.reconnectionAttempts = config['reconnection-attempts'] || 3;
    this.backoffBase = config['backoff-base'] || 1000;
    this.heartbeatInterval = config['heartbeat-interval'] || 30000;
    this.currentServerIndex = 0;
    this.reconnectAttempts = 0;
    this.subscriptions = new Set();
    this.heartbeatTimer = null;
    this.reconnectTimer = null;
    this.schemaValidator = new Ajv().compile(config['message-schema']);
    this.protobufRoot = protobuf.Root.fromJSON(config['protobuf-definition']);
    this.messageType = this.protobufRoot.lookupType('Message');
    this.connect();
  }

  connect() {
    this.ws = new WebSocket(this.serverUrls[this.currentServerIndex]);
    this.setupWebSocketHandlers();
  }

  setupWebSocketHandlers() {
    this.ws.onopen = () => this.handleConnectionOpen();
    this.ws.onmessage = (event) => this.handleMessage(event);
    this.ws.onclose = () => this.handleConnectionClose();
    this.ws.onerror = (error) => this.emit('connectionError', error);
  }

  handleConnectionOpen() {
    this.reconnectAttempts = 0;
    this.startHeartbeat();
    this.emit('connectionEstablished');
  }

  handleMessage(event) {
    const decompressed = this.messageType.decode(Buffer.from(event.data));
    if (!this.schemaValidator(decompressed)) {
      this.emit('invalidPayload', this.schemaValidator.errors);
      return;
    }
    this.emit('messageReceived', decompressed);
  }

  handleConnectionClose() {
    this.clearHeartbeat();
    if (this.reconnectAttempts < this.reconnectionAttempts) {
      this.scheduleReconnection();
    }
  }

  startHeartbeat() {
    this.heartbeatTimer = setInterval(() => {
      this.ws.ping();
      this.emit('heartbeatSent');
    }, this.heartbeatInterval);
  }

  clearHeartbeat() {
    clearInterval(this.heartbeatTimer);
  }

  scheduleReconnection() {
    const jitter = Math.random() * 500;
    const delay = Math.min(this.backoffBase * 2 ** this.reconnectAttempts, 30000) + jitter;
    this.reconnectTimer = setTimeout(() => {
      this.currentServerIndex = (this.currentServerIndex + 1) % this.serverUrls.length;
      this.reconnectAttempts++;
      this.connect();
    }, delay);
  }

  subscribeToFeed(feedId) {
    this.subscriptions.add(feedId);
    this.sendMessage({ type: 'subscriptionUpdate', feeds: [...this.subscriptions] });
  }

  unsubscribeFromFeed(feedId) {
    this.subscriptions.delete(feedId);
    this.sendMessage({ type: 'subscriptionUpdate', feeds: [...this.subscriptions] });
  }

  sendMessage(message) {
    if (this.ws.readyState === WebSocket.OPEN) {
      const encoded = this.messageType.encode(message).finish();
      this.ws.send(encoded);
    }
  }

  closeConnection() {
    this.ws.close();
    this.clearHeartbeat();
    clearTimeout(this.reconnectTimer);
  }
}
