package main

import (
    "bytes"
    "compress/gzip"
    "crypto/tls"
    "fmt"
    "regexp"
    "time"

    "github.com/aws/aws-sdk-go/aws"
    "github.com/aws/aws-sdk-go/aws/session"
    "github.com/aws/aws-sdk-go/service/s3/s3manager"
)

type LogAggregator struct {
    logs            bytes.Buffer
    max_size        int
    rotation_time   time.Duration
    last_rotation   time.Time
    tls_config      *tls.Config
    compression_lvl int
}

func (la *LogAggregator) IngestLogs(data []byte) error {
    var buf bytes.Buffer
    gz, _ := gzip.NewWriterLevel(&buf, la.compression_lvl)
    if _, err := gz.Write(data); err != nil {
        return err
    }
    gz.Close()

    la.logs.Write(buf.Bytes())
    la.rotateLogsIfNeeded()
    return nil
}

func (la *LogAggregator) FilterLogs(pattern string) ([]string, error) {
    re, err := regexp.Compile(pattern)
    if err != nil {
        return nil, err
    }

    var matches []string
    rawLogs := la.logs.Bytes()
    for _, line := range bytes.Split(rawLogs, []byte{'\n'}) {
        if re.Match(line) {
            matches = append(matches, string(line))
        }
    }
    return matches, nil
}

func (la *LogAggregator) ExportBatchToS3(bucket, key string) error {
    sess := session.Must(session.NewSession())
    uploader := s3manager.NewUploader(sess)

    _, err := uploader.Upload(&s3manager.UploadInput{
        Bucket: aws.String(bucket),
        Key:    aws.String(key),
        Body:   bytes.NewReader(la.logs.Bytes()),
    })
    return err
}

func (la *LogAggregator) rotateLogsIfNeeded() {
    if la.logs.Len() >= la.max_size || time.Since(la.last_rotation) > la.rotation_time {
        la.logs.Reset()
        la.last_rotation = time.Now()
    }
}
