use aes::Aes256;
use block_modes::{BlockMode, Cbc, block_padding::Pkcs7};
use rand::Rng;
use std::collections::HashMap;
use std::sync::{Arc, Mutex};

type Aes256Cbc = Cbc<Aes256, Pkcs7>;

pub struct SecureStorage {
    data: Arc<Mutex<HashMap<String, (Vec<u8>, Vec<u8>)>>>,
    encryption_key: Vec<u8>,
}

impl SecureStorage {
    pub fn new(encryption_key: Vec<u8>) -> Result<Self, StorageError> {
        if encryption_key.len() != 32 {
            return Err(StorageError::InvalidKeyLength);
        }
        Ok(Self {
            data: Arc::new(Mutex::new(HashMap::new())),
            encryption_key,
        })
    }

    pub fn store_data(&self, key: String, value: Vec<u8>) -> Result<(), StorageError> {
        let mut iv = [0u8; 16];
        rand::thread_rng().fill(&mut iv);
        let cipher = Aes256Cbc::new_from_slices(&self.encryption_key, &iv)
            .map_err(|_| StorageError::EncryptionError)?;
        let ciphertext = cipher.encrypt_vec(&value);
        let mut data = self.data.lock().unwrap();
        data.insert(key, (ciphertext, iv.to_vec()));
        Ok(())
    }

    pub fn retrieve_data(&self, key: &str) -> Result<Vec<u8>, StorageError> {
        let data = self.data.lock().unwrap();
        let (ciphertext, iv) = data.get(key).ok_or(StorageError::NotFound)?;
        let cipher = Aes256Cbc::new_from_slices(&self.encryption_key, iv)
            .map_err(|_| StorageError::DecryptionError)?;
        let decrypted = cipher.decrypt_vec(ciphertext)
            .map_err(|_| StorageError::DecryptionError)?;
        Ok(decrypted)
    }

    pub fn delete_data(&self, key: &str) -> Result<(), StorageError> {
        let mut data = self.data.lock().unwrap();
        data.remove(key).ok_or(StorageError::NotFound)?;
        Ok(())
    }
}

#[derive(Debug)]
pub enum StorageError {
    InvalidKeyLength,
    NotFound,
    EncryptionError,
    DecryptionError,
}
