package FileManager

import (
	"errors"
	"sync"
)

type FileManager struct {
	mu    sync.RWMutex
	files map[string][]byte
}

func New() *FileManager {
	return &FileManager{
		files: make(map[string][]byte),
	}
}

func (fm *FileManager) UploadFile(filePath string, content []byte) error {
	fm.mu.Lock()
	defer fm.mu.Unlock()

	if _, exists := fm.files[filePath]; exists {
		return errors.New("file already exists")
	}

	fm.files[filePath] = content
	return nil
}

func (fm *FileManager) DownloadFile(filePath string) ([]byte, error) {
	fm.mu.RLock()
	defer fm.mu.RUnlock()

	content, exists := fm.files[filePath]
	if !exists {
		return nil, errors.New("file not found")
	}

	return content, nil
}

func (fm *FileManager) DeleteFile(filePath string) error {
	fm.mu.Lock()
	defer fm.mu.Unlock()

	if _, exists := fm.files[filePath]; !exists {
		return errors.New("file not found")
	}

	delete(fm.files, filePath)
	return nil
}
