import random
import asyncpg

class SensorMonitor:
    def __init__(self, sensor_ids, db_config, window_size=5):
        self.sensor_ids = sensor_ids
        self.db_config = db_config
        self.window_size = window_size
        self.data_windows = {s_id: deque(maxlen=window_size) for s_id in sensor_ids}

    async def read_sensor(self, sensor_id):
        try:
            return {
                "sensor_id": sensor_id,
                "value": random.uniform(0, 100),
                "timestamp": datetime.now()
            }
        except Exception as e:
            print(f"Read error on {sensor_id}: {e}")
            raise

    def filter_data(self, sensor_id, data):
        self.data_windows[sensor_id].append(data["value"])
        if len(self.data_windows[sensor_id]) < self.window_size:
            return None
        return sum(self.data_windows[sensor_id]) / self.window_size

    async def store_result(self, sensor_id, filtered_value):
        try:
            conn = await asyncpg.connect(**self.db_config)
            await conn.execute(
                "INSERT INTO sensor_data (sensor_id, value, timestamp) VALUES ($1, $2, $3)",
                sensor_id, filtered_value, datetime.now()
            )
            await conn.close()
        except Exception as e:
            print(f"Storage error on {sensor_id}: {e}")
            raise

    async def _monitor_task(self, sensor_id):
        while True:
            try:
                data = await self.read_sensor(sensor_id)
                smoothed = self.filter_data(sensor_id, data)
                if smoothed is not None:
                    await self.store_result(sensor_id, smoothed)
                await asyncio.sleep(1)
            except Exception as e:
                print(f"Monitoring interrupted for {sensor_id}: {e}")
                await asyncio.sleep(5)

    async def start_monitoring(self):
        tasks = [asyncio.create_task(self._monitor_task(s_id)) for s_id in self.sensor_ids]
        await asyncio.gather(*tasks)
