#include <iostream>
#include <fstream>
#include <vector>
#include <algorithm>
#include <stdexcept>
#include <sstream>
#include <cctype>

using namespace std;

class LogAnalyzer {
private:
    struct LogEntry {
        string timestamp;
        string severity;
        string message;
    };

    vector<LogEntry> entries;

public:
    void parseLog(const string& filename) {
        ifstream file(filename);
        if (!file.is_open()) {
            throw runtime_error("Unable to open file: " + filename);
        }

        string line;
        while (getline(file, line)) {
            try {
                size_t ts_end = line.find(']');
                if (ts_end == string::npos) throw invalid_argument("Invalid timestamp format");

                string timestamp = line.substr(1, ts_end - 1);
                string remaining = line.substr(ts_end + 1);
                remaining.erase(0, remaining.find_first_not_of(" \t"));

                size_t severity_end = remaining.find(' ');
                if (severity_end == string::npos) throw invalid_argument("Missing severity/message");

                string severity = remaining.substr(0, severity_end);
                string message = remaining.substr(severity_end + 1);
                transform(severity.begin(), severity.end(), severity.begin(), ::toupper);

                entries.push_back({timestamp, severity, message});
            } catch (const exception& e) {
                cerr << "Error parsing line: " << e.what() << endl;
            }
        }
    }

    vector<LogEntry> filterEntries(const string& severity) {
        vector<LogEntry> result;
        string upperSeverity = severity;
        transform(upperSeverity.begin(), upperSeverity.end(), upperSeverity.begin(), ::toupper);

        for (const auto& entry : entries) {
            if (entry.severity == upperSeverity) {
                result.push_back(entry);
            }
        }
        return result;
    }

    string generateReport() {
        int infoCount = 0, warningCount = 0, errorCount = 0;
        vector<LogEntry> errors;

        for (const auto& entry : entries) {
            if (entry.severity == "INFO") infoCount++;
            else if (entry.severity == "WARNING") warningCount++;
            else if (entry.severity == "ERROR") { errorCount++; errors.push_back(entry); }
        }

        stringstream report;
        report << "Log Analysis Report:\n"
               << "Total Entries: " << entries.size() << "\n"
               << "INFO: " << infoCount << "\n"
               << "WARNING: " << warningCount << "\n"
               << "ERROR: " << errorCount << "\n\nError Entries:\n";

        for (const auto& err : errors) {
            report << "[" << err.timestamp << "] " << err.message << "\n";
        }

        return report.str();
    }
};
