use std::fs::File;
use std::io::{self, BufReader, BufWriter, Read, Write};
use flate2::Compression;
use flate2::read::GzDecoder;
use flate2::write::GzEncoder;
use bzip2::read::BzDecoder;
use bzip2::write::BzEncoder;
use lz4::{Decoder, Encoder};

pub enum CompressionAlgorithm {
    Gzip,
    Bzip2,
    LZ4,
}

pub struct FileCompressor {
    algorithm: CompressionAlgorithm,
}

impl FileCompressor {
    pub fn new(algorithm: CompressionAlgorithm) -> Self {
        FileCompressor { algorithm }
    }

    pub fn compress_file(&self, input_path: &str, output_path: &str) -> io::Result<()> {
        let input = BufReader::new(File::open(input_path)?);
        let output = BufWriter::new(File::create(output_path)?);

        match self.algorithm {
            CompressionAlgorithm::Gzip => {
                let mut encoder = GzEncoder::new(output, Compression::default());
                io::copy(&mut input.bytes().map(|b| b.unwrap()), &mut encoder)?;
                encoder.finish()?;
            }
            CompressionAlgorithm::Bzip2 => {
                let mut encoder = BzEncoder::new(output, bzip2::Compression::default());
                io::copy(&mut input.bytes().map(|b| b.unwrap()), &mut encoder)?;
                encoder.finish()?;
            }
            CompressionAlgorithm::LZ4 => {
                let mut encoder = Encoder::new(output).map_err(|e| io::Error::new(io::ErrorKind::Other, e))?;
                io::copy(&mut input.bytes().map(|b| b.unwrap()), &mut encoder)?;
                let (_, result) = encoder.finish();
                result.map_err(|e| io::Error::new(io::ErrorKind::Other, e))?;
            }
        }
        Ok(())
    }

    pub fn decompress_file(&self, input_path: &str, output_path: &str) -> io::Result<()> {
        let input = BufReader::new(File::open(input_path)?);
        let mut output = BufWriter::new(File::create(output_path)?);

        match self.algorithm {
            CompressionAlgorithm::Gzip => {
                let mut decoder = GzDecoder::new(input);
                io::copy(&mut decoder, &mut output)?;
            }
            CompressionAlgorithm::Bzip2 => {
                let mut decoder = BzDecoder::new(input);
                io::copy(&mut decoder, &mut output)?;
            }
            CompressionAlgorithm::LZ4 => {
                let mut decoder = Decoder::new(input).map_err(|e| io::Error::new(io::ErrorKind::Other, e))?;
                io::copy(&mut decoder, &mut output)?;
            }
        }
        Ok(())
    }
}
