import pandas as pd
from concurrent.futures import ThreadPoolExecutor
import sqlalchemy
from typing import Generator

class DataPipeline:
    def extract_data(self, source_type: str, **kwargs) -> Generator[pd.DataFrame, None, None]:
        chunk_size = kwargs.get('chunk_size', 1000)
        if source_type == 'csv':
            return pd.read_csv(kwargs['file_path'], chunksize=chunk_size)
        elif source_type == 'json':
            return pd.read_json(kwargs['file_path'], chunksize=chunk_size, lines=True)
        elif source_type == 'database':
            engine = sqlalchemy.create_engine(kwargs['db_connection'])
            return pd.read_sql_query(kwargs['query'], engine, chunksize=chunk_size)
        else:
            raise ValueError(f"Unsupported source type: {source_type}")

    def transform_data(self, data: pd.DataFrame) -> pd.DataFrame:
        data = data.dropna()
        return data

    def load_data(self, data: pd.DataFrame, destination: dict) -> None:
        if destination['type'] == 'database':
            data.to_sql(destination['table_name'], destination['engine'], if_exists='append', index=False)
        elif destination['type'] == 'file':
            data.to_csv(destination['path'], mode='a', header=not destination.get('header_written', False), index=False)
            destination['header_written'] = True
        else:
            raise ValueError(f"Unsupported destination type: {destination['type']}")

    def run_etl(self, source_type: str, destination: dict, **kwargs) -> None:
        with ThreadPoolExecutor() as executor:
            for chunk in self.extract_data(source_type, **kwargs):
                transformed = self.transform_data(chunk)
                executor.submit(self.load_data, transformed, destination)
