import requests
import time
from dataclasses import dataclass

@dataclass
class ParsedResponse:
    status_code: int
    data: dict

class api_client:
    def __init__(self, config):
        self.base_url = config.get("base-url")
        self.api_key = config.get("api-key")
        self.max_retries = config.get("max-retries", 5)
        self.base_delay = config.get("base-delay", 1)
        self.session = requests.Session()
        if self.api_key:
            self.session.headers.update({"Authorization": f"Bearer {self.api_key}"})

    def get_transaction_graph(self, params=None):
        url = f"{self.base_url}/get-transaction-graph"
        response = self.handle_rate_limiting("GET", url, params=params)
        response.raise_for_status()
        return ParsedResponse(response.status_code, response.json())

    def post_smart_contract(self, abi_data):
        self._validate_abi(abi_data)
        url = f"{self.base_url}/post-smart-contract"
        response = self.handle_rate_limiting("POST", url, json=abi_data)
        response.raise_for_status()
        return ParsedResponse(response.status_code, response.json())

    def handle_rate_limiting(self, method, url, **kwargs):
        retries = 0
        while retries <= self.max_retries:
            response = self.session.request(method, url, **kwargs)
            if response.status_code != 429:
                return response
            delay = self.base_delay * (2 ** retries)
            time.sleep(delay)
            retries += 1
        return response

    def _validate_abi(self, abi):
        if not isinstance(abi, list):
            raise ValueError("ABI must be a list")
        for entry in abi:
            if not isinstance(entry, dict):
                raise ValueError("ABI entries must be dictionaries")
            if "type" not in entry:
                raise ValueError("ABI entry missing 'type'")
