public class kafkaConfig
{
    public string bootstrapServers { get; set; }
    public string groupId { get; set; }
}

public static class serialization_handler
{
    public static byte[] SerializePayload<T>(T payload) => MessagePackSerializer.Serialize(payload);
}

public class MessageBroker
{
    private readonly IConsumer<Ignore, byte[]> _consumer;
    private readonly IProducer<Null, byte[]> _producer;

    public MessageBroker(kafkaConfig config)
    {
        _consumer = new ConsumerBuilder<Ignore, byte[]>(new ConsumerConfig
        {
            BootstrapServers = config.bootstrapServers,
            GroupId = config.groupId,
            AutoOffsetReset = AutoOffsetReset.Earliest
        }).Build();

        _producer = new ProducerBuilder<Null, byte[]>(new ProducerConfig
        {
            BootstrapServers = config.bootstrapServers
        }).Build();
    }

    public void StartConsuming()
    {
        _consumer.Subscribe(TopicRegistry.OrderTopic);
        while (true)
        {
            try
            {
                var result = _consumer.Consume();
                ProcessMessage(result.Message.Value);
            }
            catch (ConsumeException ex)
            {
                HandleDeadLetter(ex.Error.Code.ToString(), ex.Message.Value, ErrorCode.ProcessingError);
            }
        }
    }

    private void HandleDeadLetter(string errorCode, byte[] message, ErrorCode errorType)
    {
        for (int i = 0; i < 3; i++)
        {
            try
            {
                ProcessMessage(message);
                return;
            }
            catch
            {
                if (i == 2)
                {
                    var deadLetter = new
                    {
                        Payload = message,
                        Error = errorCode,
                        Timestamp = DateTime.UtcNow
                    };
                    _producer.Produce(TopicRegistry.DeadLetterTopic, new Message<Null, byte[]>
                    {
                        Value = serialization_handler.SerializePayload(deadLetter)
                    });
                }
                System.Threading.Thread.Sleep(1000 * (int)Math.Pow(2, i));
            }
        }
    }

    private void ProcessMessage(byte[] message)
    {
