package network_monitor

import (
	"fmt"
	"net"
	"sync"
	"time"
)

type network_monitor struct {
	mu                 sync.Mutex
	active_connections map[string]net.Conn
	bandwidth_in       uint64
	bandwidth_out      uint64
	anomalies          chan string
	done               chan struct{}
}

func NewNetworkMonitor() *network_monitor {
	return &network_monitor{
		active_connections: make(map[string]net.Conn),
		anomalies:          make(chan string),
		done:               make(chan struct{}),
	}
}

func (nm *network_monitor) MonitorTraffic() {
	go func() {
		ticker := time.NewTicker(1 * time.Second)
		defer ticker.Stop()
		for {
			select {
			case <-ticker.C:
				nm.mu.Lock()
				bw_in := nm.bandwidth_in
				bw_out := nm.bandwidth_out
				nm.bandwidth_in, nm.bandwidth_out = 0, 0
				nm.mu.Unlock()
				fmt.Printf("Bandwidth In: %d, Out: %d\n", bw_in, bw_out)
			case <-nm.done:
				return
			}
		}
	}()
}

func (nm *network_monitor) DetectIntrusion() {
	go func() {
		ticker := time.NewTicker(5 * time.Second)
		defer ticker.Stop()
		for {
			select {
			case <-ticker.C:
				nm.mu.Lock()
				if len(nm.active_connections) > 100 {
					nm.anomalies <- "suspicious connection count"
				}
				nm.mu.Unlock()
			case <-nm.done:
				return
			}
		}
	}()
}

func (nm *network_monitor) LogActivity() {
	go func() {
		for {
			select {
			case anomaly := <-nm.anomalies:
				fmt.Printf("Anomaly: %s\n", anomaly)
			case <-nm.done:
				return
			}
		}
	}()
}

func (nm *network_monitor) Stop() {
	close(nm.done)
}
