class CryptoWallet {
    #private_keys = [];

    constructor(private_keys = []) {
        this.#private_keys = [...private_keys];
    }

    sendTransaction(recipient_address, amount, private_key) {
        if (!this.#private_keys.includes(private_key)) {
            throw new Error('Private key not managed');
        }
        const transaction = {
            from: this.#getAddressFromPrivateKey(private_key),
            to: recipient_address,
            value: amount
        };
        const signed_transaction = this.#signTransaction(transaction, private_key);
        return this.#broadcastTransaction(signed_transaction);
    }

    async getBalance(address, provider_url) {
        const response = await fetch(`${provider_url}/balance/${address}`);
        const data = await response.json();
        return data.balance;
    }

    manageKeys(action, key) {
        if (action === 'add') {
            this.#private_keys.push(key);
        } else if (action === 'remove') {
            this.#private_keys = this.#private_keys.filter(k => k !== key);
        }
    }

    #getAddressFromPrivateKey(private_key) {
        return `0x${Buffer.from(private_key).toString('hex').slice(0, 40)}`;
    }

    #signTransaction(transaction, private_key) {
        return JSON.stringify({ ...transaction, signature: '0x' + private_key });
    }

    #broadcastTransaction(transaction) {
        return { status: 'success', txHash: `0x${Buffer.from(transaction).toString('hex')}` };
    }
}
