package com.geofence.util;

import com.geofence.core.Point3D;

public class GeoUtils {
    public static boolean CheckWithinBoundary(Point3D point, Point3D boundary, double accuracyThreshold) {
        return CalculateHaversine(point, boundary) <= accuracyThreshold;
    }

    public static double CalculateHaversine(Point3D p1, Point3D p2) {
        double dLat = Math.toRadians(p2.getLatitude() - p1.getLatitude());
        double dLon = Math.toRadians(p2.getLongitude() - p1.getLongitude());
        double a = Math.sin(dLat/2) * Math.sin(dLat/2) +
                Math.cos(Math.toRadians(p1.getLatitude())) * Math.cos(Math.toRadians(p2.getLatitude())) *
                        Math.sin(dLon/2) * Math.sin(dLon/2);
        return 6371 * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
    }
}

